import { interpolateRgb } from 'd3-interpolate';

import { _getCanvasColor as getCanvasColor } from '@dynatrace/strato-components/charts';
import Colors from '@dynatrace/strato-design-tokens/colors';

export const calculateHoveredColor = (color: string) => {
  return interpolateRgb(
    getCanvasColor(color),
    getCanvasColor(Colors.Background.Field.Neutral.DefaultHover),
  )(0.3);
};
